// Initialize daily lesson display
let currentDay = 1;

export function initDailyLessons() {
    loadLesson(currentDay);
    buildLessonIndex();
    
    document.getElementById('prevDayBtn')?.addEventListener('click', () => {
        if (currentDay > 1) {
            currentDay--;
            loadLesson(currentDay);
            scrollToLessonCard();
        }
    });
    
    document.getElementById('nextDayBtn')?.addEventListener('click', () => {
        if (dailyLessons[currentDay + 1]) {
            currentDay++;
            loadLesson(currentDay);
            scrollToLessonCard();
        }
    });

    const toggle = document.getElementById('lessonIndexToggle');
    const panel = document.getElementById('lessonIndexPanel');
    if (toggle && panel) {
        toggle.addEventListener('click', () => {
            const isOpen = !panel.hasAttribute('hidden');
            if (isOpen) {
                panel.setAttribute('hidden', '');
                toggle.setAttribute('aria-expanded', 'false');
                toggle.classList.remove('is-open');
            } else {
                panel.removeAttribute('hidden');
                toggle.setAttribute('aria-expanded', 'true');
                toggle.classList.add('is-open');
                highlightActiveIndexDay();
            }
        });
    }
}

function buildLessonIndex() {
    const grid = document.getElementById('lessonIndexGrid');
    if (!grid) return;
    grid.innerHTML = '';

    const days = Object.keys(dailyLessons)
        .map(n => parseInt(n, 10))
        .filter(n => !isNaN(n))
        .sort((a, b) => a - b);

    days.forEach(day => {
        const lesson = dailyLessons[day];
        const btn = document.createElement('button');
        btn.type = 'button';
        btn.className = 'lesson-index-btn';
        btn.dataset.day = String(day);
        btn.innerHTML = `
            <span class="lesson-index-day-num">Day ${day}</span>
            <span class="lesson-index-day-title">${lesson.title || ''}</span>
        `;
        btn.addEventListener('click', () => {
            currentDay = day;
            loadLesson(currentDay);
            highlightActiveIndexDay();
            scrollToLessonCard();
        });
        grid.appendChild(btn);
    });
}

function highlightActiveIndexDay() {
    const grid = document.getElementById('lessonIndexGrid');
    if (!grid) return;
    grid.querySelectorAll('.lesson-index-btn').forEach(btn => {
        btn.classList.toggle('active', parseInt(btn.dataset.day, 10) === currentDay);
    });
}

function scrollToLessonCard() {
    const card = document.querySelector('.daily-lesson-card');
    if (card && typeof card.scrollIntoView === 'function') {
        card.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }
}

async function loadLesson(day) {
    const lesson = dailyLessons[day];
    if (!lesson) return;
    
    // Import translation function
    const { t, currentLanguage } = await import('./translations.js?v=20260426c');
    const dayText = t('day');
    
    // Show/hide lesson content notice based on language
    const noticeElement = document.getElementById('lessonContentNotice');
    if (noticeElement) {
        noticeElement.style.display = currentLanguage === 'he' ? 'block' : 'none';
    }
    
    document.getElementById('lessonDay').textContent = `${dayText} ${day}`;
    document.getElementById('lessonContent').innerHTML = `
        <h5>${lesson.title}</h5>
        <p style="color: #666; font-size: 0.9em; font-style: italic;">${lesson.section}</p>
        ${lesson.content}
        <div class="lesson-completion" style="margin-top: 30px; padding-top: 20px; border-top: 1px solid #e0e0e0; text-align: center;">
            <label class="completion-checkbox-label">
                <input type="checkbox" id="lessonCheckbox" data-day="${day}">
                <span data-i18n="iLearnedLesson">✓ I learned this lesson</span>
            </label>
            <button id="saveLessonBtn" class="save-lesson-btn" data-day="${day}" data-i18n="saveProgress">Save Progress</button>
            <div id="saveMessage" class="save-message"></div>
            
            <div class="share-lesson-section" style="margin-top: 20px; padding-top: 20px; border-top: 1px solid #e0e0e0;">
                <h5 style="font-size: 1em; margin-bottom: 10px;" data-i18n="shareAccomplishment">📤 Share this accomplishment:</h5>
                <div class="share-buttons-lesson">
                    <button class="share-btn whatsapp" data-day="${day}" data-title="${lesson.title}" data-i18n="whatsappBtn">
                        💬 WhatsApp
                    </button>
                    <button class="share-btn sms" data-day="${day}" data-title="${lesson.title}" data-i18n="textBtn">
                        📱 Text
                    </button>
                    <button class="share-btn twitter" data-day="${day}" data-title="${lesson.title}" data-i18n="twitterBtn">
                        🐦 Twitter
                    </button>
                    <button class="share-btn copy" data-day="${day}" data-title="${lesson.title}" data-i18n="copyLinkBtn">
                        📋 Copy Link
                    </button>
                </div>
            </div>
        </div>
    `;
    
    // Update UI language for dynamically added content
    const { updateUILanguage } = await import('./translations.js?v=20260426c');
    updateUILanguage();
    
    // Wait a moment for DOM to be ready
    await new Promise(resolve => setTimeout(resolve, 0));
    
    const checkbox = document.getElementById('lessonCheckbox');
    const saveBtn = document.getElementById('saveLessonBtn');
    const saveMessage = document.getElementById('saveMessage');
    
    // Check if lesson is already completed
    const { auth, db, doc, getDoc } = await import('./firebase-config.js?v=20260426c');
    const user = auth.currentUser;
    
    if (user) {
        const userRef = doc(db, 'users', user.uid);
        const userDoc = await getDoc(userRef);
        const completedLessons = userDoc.data()?.completedLessons || [];
        
        if (checkbox && completedLessons.includes(day)) {
            checkbox.checked = true;
            if (saveBtn) {
                saveBtn.textContent = 'Completed ✓';
                saveBtn.classList.add('completed');
            }
        }
    } else {
        let completedLessons = [];
        try {
            completedLessons = JSON.parse(localStorage.getItem('guestCompletedLessons') || '[]');
        } catch (error) {
            completedLessons = [];
        }
        if (checkbox && completedLessons.includes(day)) {
            checkbox.checked = true;
            if (saveBtn) {
                saveBtn.textContent = 'Completed ✓';
                saveBtn.classList.add('completed');
            }
        }
    }
    
    // Add event listener for save button (outside user check)
    if (saveBtn) {
        saveBtn.addEventListener('click', async (e) => {
            e.preventDefault();
            console.log('Save button clicked!');
            
            const isChecked = checkbox ? checkbox.checked : false;
            console.log('Checkbox is checked:', isChecked);
            await toggleLessonCompletion(day, isChecked);
        });
    }
    
    // Add event listeners for share buttons
    document.querySelectorAll('.share-btn').forEach(btn => {
        btn.addEventListener('click', (e) => {
            e.preventDefault();
            const day = e.currentTarget.dataset.day;
            const title = e.currentTarget.dataset.title;
            const shareType = e.currentTarget.classList.contains('whatsapp') ? 'whatsapp' :
                             e.currentTarget.classList.contains('sms') ? 'sms' :
                             e.currentTarget.classList.contains('twitter') ? 'twitter' : 'copy';
            
            shareLesson(day, title, shareType);
        });
    });
    
    // Update button states
    const prevBtn = document.getElementById('prevDayBtn');
    const nextBtn = document.getElementById('nextDayBtn');
    
    if (prevBtn) prevBtn.disabled = (day === 1);
    if (nextBtn) nextBtn.disabled = !dailyLessons[day + 1];
}

async function toggleLessonCompletion(day, isCompleted) {
    console.log('toggleLessonCompletion called:', day, isCompleted);
    
    try {
        const { auth, db, doc, getDoc, updateDoc, arrayUnion, arrayRemove } = await import('./firebase-config.js?v=20260426c');
        const { t } = await import('./translations.js?v=20260426c');
        const user = auth.currentUser;
        
        if (!user) {
            let arr = [];
            try {
                arr = JSON.parse(localStorage.getItem('guestCompletedLessons') || '[]');
            } catch (error) {
                arr = [];
            }
            if (isCompleted) {
                if (!arr.includes(day)) arr.push(day);
            } else {
                arr = arr.filter((d) => d !== day);
            }
            arr.sort((a, b) => a - b);
            localStorage.setItem('guestCompletedLessons', JSON.stringify(arr));

            const saveMessage = document.getElementById('saveMessage');
            const saveBtn = document.getElementById('saveLessonBtn');

            if (isCompleted) {
                if (saveMessage) {
                    saveMessage.textContent = '✓ ' + t('guestSavedLocally');
                    saveMessage.style.color = '#4CAF50';
                    saveMessage.style.fontWeight = '600';
                }
                if (saveBtn) {
                    saveBtn.textContent = 'Completed ✓';
                    saveBtn.classList.add('completed');
                }
            } else {
                if (saveMessage) {
                    saveMessage.textContent = t('guestSavedLocally');
                    saveMessage.style.color = '#666';
                }
                if (saveBtn) {
                    saveBtn.textContent = 'Save Progress';
                    saveBtn.classList.remove('completed');
                }
            }
            if (saveMessage) {
                setTimeout(() => {
                    saveMessage.textContent = '';
                }, 4000);
            }
            window.dispatchEvent(new CustomEvent('lessonCompleted', { detail: { day, isCompleted } }));
            return;
        }
        
        console.log('User:', user.uid);
        
        const userRef = doc(db, 'users', user.uid);
        const saveMessage = document.getElementById('saveMessage');
        const saveBtn = document.getElementById('saveLessonBtn');
        
        if (isCompleted) {
            console.log('Adding lesson to completed list...');
            await updateDoc(userRef, {
                completedLessons: arrayUnion(day),
                lastUpdated: new Date().toISOString()
            });
            
            console.log('Lesson added successfully');
            
            // Share to community feed
            const lesson = dailyLessons[day];
            if (lesson) {
                const { collection, addDoc, serverTimestamp } = await import('./firebase-config.js?v=20260426c');
                try {
                    await addDoc(collection(db, 'communityPosts'), {
                        userId: user.uid,
                        userName: user.displayName || user.email.split('@')[0],
                        content: `Just completed "${lesson.title}"! 📖`,
                        type: 'completions',
                        day: day,
                        timestamp: serverTimestamp()
                    });
                    console.log('Shared to community feed');
                } catch (err) {
                    console.error('Error sharing to community:', err);
                }
            }
            
            if (saveMessage) {
                saveMessage.textContent = '✓ Lesson marked as completed!';
                saveMessage.style.color = '#4CAF50';
                saveMessage.style.fontWeight = '600';
            }
            
            if (saveBtn) {
                saveBtn.textContent = 'Completed ✓';
                saveBtn.classList.add('completed');
            }
        } else {
            console.log('Removing lesson from completed list...');
            await updateDoc(userRef, {
                completedLessons: arrayRemove(day),
                lastUpdated: new Date().toISOString()
            });
            
            console.log('Lesson removed successfully');
            
            if (saveMessage) {
                saveMessage.textContent = 'Lesson unmarked';
                saveMessage.style.color = '#666';
            }
            
            if (saveBtn) {
                saveBtn.textContent = 'Save Progress';
                saveBtn.classList.remove('completed');
            }
        }
        
        // Hide message after 3 seconds
        if (saveMessage) {
            setTimeout(() => {
                saveMessage.textContent = '';
            }, 3000);
        }
        
        // Trigger progress tracker update
        console.log('Dispatching lessonCompleted event');
        window.dispatchEvent(new CustomEvent('lessonCompleted', { detail: { day, isCompleted } }));
        
    } catch (error) {
        console.error('Error updating lesson completion:', error);
        const saveMessage = document.getElementById('saveMessage');
        if (saveMessage) {
            saveMessage.textContent = '❌ Error saving. Please try again.';
            saveMessage.style.color = '#f44336';
        }
    }
}

export function getCurrentDay() {
    return currentDay;
}

function shareLesson(day, title, shareType) {
    const message = `🕊️ I just completed Day ${day}: "${title}" in my Shmiras HaLashon journey! Join me in learning to guard our speech. #ChofetzChaim #ShmirasHaLashon`;
    const url = window.location.href;
    
    switch(shareType) {
        case 'whatsapp':
            const whatsappUrl = `https://wa.me/?text=${encodeURIComponent(message + '\n' + url)}`;
            window.open(whatsappUrl, '_blank');
            break;
            
        case 'sms':
            const smsUrl = `sms:?&body=${encodeURIComponent(message + '\n' + url)}`;
            window.location.href = smsUrl;
            break;
            
        case 'twitter':
            const twitterUrl = `https://twitter.com/intent/tweet?text=${encodeURIComponent(message)}&url=${encodeURIComponent(url)}`;
            window.open(twitterUrl, '_blank');
            break;
            
        case 'copy':
            navigator.clipboard.writeText(message + '\n' + url).then(() => {
                alert('✓ Copied to clipboard! Share it with your friends.');
            }).catch(() => {
                alert('Failed to copy. Please try again.');
            });
            break;
    }
}
